SELECT ?year ?method_type ?method_typeLabel (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    ?paper pgmr:has_contribution ?contribution ;
           pgmr:publication_year ?year .

    ?contribution a pgmrc:empirical_research_practice_contribution ;
                  pgmr:venue_serie ?venue ;
                  pgmr:data_collection ?data_collection .

    ?venue rdfs:label ?venue_name .

    ?data_collection rdfs:label ?dc_label ;
                     pgmr:method ?dc_method .

    ?dc_method pgmr:method_type ?method_type .

    OPTIONAL { ?method_type rdfs:label ?method_typeLabel . }

    FILTER(?dc_label != "no collection"^^xsd:string)
    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
}
GROUP BY ?year ?method_type ?method_typeLabel
ORDER BY ?year ?method_typeLabel

